{% extends 'base.html' %}

{% block title %}Game List{% endblock %}

{% block extra_css %}
<style>
    .page-title {
        color: #1e3a8a;
        margin-bottom: 16px;
    }

    .game-grid {
        display: grid;
        gap: 14px;
    }

    .game-card {
        background: #ffffff;
        border: 1px solid #dbe3ef;
        border-radius: 10px;
        padding: 16px;
    }

    .game-card h3 {
        color: #5f73e8;
        margin-bottom: 8px;
    }

    .meta {
        color: #4b5563;
        margin-bottom: 6px;
    }

    .tag-pill {
        display: inline-block;
        background: #e0e7ff;
        color: #3730a3;
        border-radius: 999px;
        padding: 4px 8px;
        margin-right: 6px;
        margin-bottom: 6px;
        font-size: 0.85rem;
    }

    .muted {
        color: #6b7280;
    }
</style>
{% endblock %}

{% block content %}
<h2 class="page-title">Game List</h2>

<div class="game-grid">
    {% for game in games %}
        <article class="game-card">
            <h3>{{ game.title }}</h3>
            <p class="meta"><strong>Developer:</strong> {{ game.developer }}</p>
            <p class="meta"><strong>Platform:</strong> {{ game.platform }}</p>
            <div>
                <strong>Tags:</strong>
                {% for tag in game.label_tag.all %}
                    <span class="tag-pill">{{ tag.label }}</span>
                {% empty %}
                    <span class="muted">No tags</span>
                {% endfor %}
            </div>
        </article>
    {% empty %}
        <p class="muted">No games available. Add your first game.</p>
    {% endfor %}
</div>
{% endblock %}

{% extends 'base.html' %}

{% block title %}Game List{% endblock %}

{% block extra_css %}
<style>
    .page-title {
        color: #1e3a8a;
        margin-bottom: 16px;
    }

    .page-subtitle {
        color: #64748b;
        margin-bottom: 18px;
    }

    .game-grid {
        display: grid;
        grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
        gap: 16px;
    }

    .game-card {
        background: #ffffff;
        border: 1px solid #dbe3ef;
        border-top: 4px solid #5f73e8;
        border-radius: 12px;
        padding: 18px;
        box-shadow: 0 8px 18px rgba(15, 23, 42, 0.06);
    }

    .game-card h3 {
        color: #5f73e8;
        margin-bottom: 10px;
        font-size: 1.25rem;
    }

    .meta {
        color: #4b5563;
        margin-bottom: 8px;
    }

    .summary {
        background: #f8fafc;
        border-left: 4px solid #5f73e8;
        padding: 10px 12px;
        border-radius: 6px;
        margin: 12px 0;
        color: #334155;
    }

    .tag-pill {
        display: inline-block;
        background: #e0e7ff;
        color: #3730a3;
        border-radius: 999px;
        padding: 4px 8px;
        margin-right: 6px;
        margin-bottom: 6px;
        font-size: 0.85rem;
    }

    .muted {
        color: #6b7280;
    }

    .empty-state {
        background: #ffffff;
        border: 1px dashed #cbd5e1;
        border-radius: 12px;
        padding: 22px;
        color: #64748b;
    }
</style>
{% endblock %}

{% block content %}
<h2 class="page-title">Game List</h2>
<p class="page-subtitle">Browse the sample collection with tags and platform details.</p>

<div class="game-grid">
    {% for game in games %}
        <article class="game-card">
            <h3>{{ game.title }}</h3>
            <p class="meta"><strong>Developer:</strong> {{ game.developer }}</p>
            <p class="meta"><strong>Platform:</strong> {{ game.platform }}</p>
            <div class="summary">{{ game.developer }} on {{ game.platform }} with {{ game.label_tag.count }} tag{{ game.label_tag.count|pluralize }}</div>
            <div>
                <strong>Tags:</strong>
                {% for tag in game.label_tag.all %}
                    <span class="tag-pill">{{ tag.label }}</span>
                {% empty %}
                    <span class="muted">No tags</span>
                {% endfor %}
            </div>
        </article>
    {% empty %}
        <div class="empty-state">No games available. Add your first game or seed the demo data.</div>
    {% endfor %}
</div>
{% endblock %}

{% extends 'base.html' %}

{% block title %}Reviews{% endblock %}

{% block extra_css %}
<style>
    body {
        background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    }

    .page-header {
        text-align: center;
        color: #ffffff;
        margin-bottom: 28px;
        padding: 20px 0 10px;
    }

    .page-header h2 {
        font-size: 2.2rem;
        margin-bottom: 8px;
        text-shadow: 2px 2px 4px rgba(0, 0, 0, 0.2);
    }

    .page-header p {
        font-size: 1rem;
        opacity: 0.9;
    }

    .review-list {
        display: grid;
        gap: 20px;
        margin-bottom: 24px;
    }

    .card {
        background: #fff;
        border-radius: 12px;
        padding: 24px;
        box-shadow: 0 8px 16px rgba(0, 0, 0, 0.15);
        transition: transform 0.3s ease, box-shadow 0.3s ease;
    }

    .card:hover {
        transform: translateY(-4px);
        box-shadow: 0 12px 24px rgba(0, 0, 0, 0.2);
    }

    .card h2 {
        color: #5f73e8;
        font-size: 1.7rem;
        margin-bottom: 12px;
        border-bottom: 3px solid #5f73e8;
        padding-bottom: 10px;
    }

    .meta {
        color: #4b5563;
        margin-bottom: 8px;
        font-size: 0.95rem;
    }

    .review-text {
        color: #333;
        line-height: 1.6;
        background: #f8f9fa;
        border-left: 4px solid #5f73e8;
        padding: 14px;
        border-radius: 4px;
        margin: 14px 0;
    }

    .tags {
        margin-top: 12px;
    }

    .tag-pill {
        display: inline-block;
        background: #e0e7ff;
        color: #3730a3;
        padding: 4px 8px;
        border-radius: 999px;
        margin-right: 6px;
        margin-bottom: 6px;
        font-size: 0.85rem;
    }

    .muted {
        color: #6b7280;
    }

    .actions {
        margin-top: 14px;
    }

    .btn-delete {
        display: inline-block;
        background: #dc2626;
        color: #ffffff;
        text-decoration: none;
        border-radius: 6px;
        padding: 7px 10px;
        font-size: 0.85rem;
        font-weight: 600;
    }

    .btn-delete:hover {
        background: #b91c1c;
    }

    .empty-state {
        background: #ffffff;
        border-radius: 12px;
        padding: 50px 20px;
        text-align: center;
        box-shadow: 0 8px 16px rgba(0, 0, 0, 0.15);
    }

    @media (max-width: 768px) {
        .page-header h2 {
            font-size: 1.8rem;
        }

        .card {
            padding: 18px;
        }

        .card h2 {
            font-size: 1.4rem;
        }
    }
</style>
{% endblock %}

{% block content %}
<section class="page-header">
    <h2>Game Reviews</h2>
    <p>Discover what players think about their favorite games</p>
</section>

<div class="review-list">
    {% for review in reviews %}
        <article class="card">
            <h2>{{ review.game.title }}</h2>
            <p class="meta"><strong>Developer:</strong> {{ review.game.developer }}</p>
            <p class="meta"><strong>Platform:</strong> {{ review.game.platform }}</p>

            <p class="review-text">{{ review.review }}</p>
            <p class="meta"><strong>Date:</strong> {{ review.date|date:"M d, Y" }}</p>

            <div class="tags">
                <strong>Tags:</strong>
                {% for tag in review.game.label_tag.all %}
                    <span class="tag-pill">{{ tag.label }}</span>
                {% empty %}
                    <span class="muted">No tags</span>
                {% endfor %}
            </div>

            <div class="actions">
                <a href="{% url 'review_delete' review.pk %}" class="btn-delete">Delete Review</a>
            </div>
        </article>
    {% empty %}
        <div class="empty-state">
            <p class="muted">No reviews yet. Be the first to add one!</p>
        </div>
    {% endfor %}
</div>
{% endblock %}

